					NomadEnvironment.GetTrace().Info("****** Validación de Password ******");

NomadXML docUSUARIO = new Nomad.NSystem.Proxy.NomadXML("USUARIO"); 

//inicio encriptacion  ValidatePass

//obtiene clave guardada en bd con ObtenerPassUsuario
string clave_entrada;
string param_pass = "<ROW oi_tipo_documento = '" + XML_LOGIN.FirstChild().GetAttr("oi_tipo_documento") + "' c_nro_doc = '" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "'/>";     
NomadXML docPASS = new Nomad.NSystem.Proxy.NomadXML("PASS"); 
docPASS = NomadEnvironment.QueryNomadXML(CV.Resources.ObtenerPassUsuario, param_pass).FirstChild();

//si la clave guardada está encriptada, se encripta también la clave de entrada 
if (((docPASS.GetAttrString("c_password").Length == 35) && (docPASS.GetAttrString("c_password").Split('-').Length == 4)))
{
    clave_entrada = StringUtil.GetMD5("|" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "|" + XML_LOGIN.FirstChild().GetAttr("c_password")+"|");
}  
//si la clave guardada no está encriptada, la de entrada queda como venía
else
{   clave_entrada = XML_LOGIN.FirstChild().GetAttr("c_password"); }

//log nuevo 1
NomadEnvironment.GetTrace().Info("clave_entrada: " + clave_entrada.ToString());

//fin encriptacion   ValidatePass

string param = "<ROW oi_tipo_documento = '" + XML_LOGIN.FirstChild().GetAttr("oi_tipo_documento") + "' c_nro_doc = '" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "' c_password = '" + clave_entrada + "'/>";     
NomadEnvironment.GetTrace().Info("param: " + param.ToString());
docUSUARIO = NomadEnvironment.QueryNomadXML(CV.Resources.getUsuario, param).FirstChild();
NomadEnvironment.GetTrace().Info("docUSUARIO: " + docUSUARIO.ToString());
NomadXML docSALIDA = new Nomad.NSystem.Proxy.NomadXML("OUT");     

if(docUSUARIO.GetAttrString("oi_cv") != "0") { 

  //si pasa validacion de clave, y no estaba encriptada, la encripta y la guarda
  if (!((clave_entrada.Length == 35) && (clave_entrada.Split('-').Length == 4)))
  {
    NucleusRH.Base.Postulantes.CV.CV objCV;        
    objCV = NucleusRH.Base.Postulantes.CV.CV.Get(docUSUARIO.GetAttr("oi_cv"));
    objCV.c_password = StringUtil.GetMD5("|" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "|" + XML_LOGIN.FirstChild().GetAttr("c_password")+"|");
    NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV); 
    //log nuevo 2
    NomadEnvironment.GetTrace().Info("c_pass: " + objCV.c_password.ToString());
  }  

  //fin guardar clave encriptada


	docUSUARIO.AddXML(NomadEnvironment.QueryNomadXML(CV.Resources.getDatosUsuario, param).FirstChild());
	docUSUARIO.SetAttr("out","OK");
	return docUSUARIO;
}
else {
	docSALIDA.SetAttr("out","Error al intentar loguearse.");
	return docSALIDA;
}

