return docUSUARIO;

					NomadLog.Info("****** Save CV ******");
NomadLog.Info("XML_CV: " + XML_CV.ToString());
string param = "<ROW oi_tipo_documento = '" + XML_CV.FirstChild().GetAttr("oi_tipo_documento") + "' c_nro_doc = '" + XML_CV.FirstChild().GetAttr("c_nro_doc")+"'/>";
