int nuevoCV = 0;
NucleusRH.Base.Postulantes.CV.CV objCV;        
Nomad.Base.Mail.OutputMails.MAIL MyMAIL;
Nomad.Base.Mail.OutputMails.DESTINATARIO MyDEST;

if(docUSUARIO.GetAttrString("oi_cv") != "0" || XML_CV.FirstChild().GetAttr("oi_cv") != "") 
{
	objCV = NucleusRH.Base.Postulantes.CV.CV.Get(docUSUARIO.GetAttr("oi_cv"));
}
else 
{
	objCV = new NucleusRH.Base.Postulantes.CV.CV();
	objCV.l_alta_web         = true; 
	objCV.c_origen 					 = "WEB";
	objCV.f_alta_cv          = DateTime.Now;
	objCV.c_cv							 = "WEB" + XML_CV.FirstChild().GetAttr("c_nro_doc"); 
	objCV.c_nro_doc          = XML_CV.FirstChild().GetAttr("c_nro_doc"); 

	//inicio encriptacion SaveCV
	if (XML_CV.FirstChild().GetAttr("c_password") != "")
  {
    objCV.c_password = XML_CV.FirstChild().GetAttr("c_password");

       //No esta encriptado
       if (!((objCV.c_password.Length == 35) && (objCV.c_password.Split('-').Length == 4)))
                  {
                      //Encripto la clave
                      objCV.c_password = StringUtil.GetMD5("|" + objCV.c_nro_doc.ToString() + "|" + objCV.c_password+"|");
                  }
  }
  else
  {
    objCV.c_password = null;
  }

	//fin encriptacion SaveCV

	nuevoCV = 1;
}

objCV.d_apellido          = XML_CV.FirstChild().GetAttr("d_apellido");
