NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV);

NomadLog.Info("Agrego los Estudios");
////////////////////////////////////////////////////////////////////////////////////////////
////////////////////////             Agrego los Estudios            ////////////////////////
////////////////////////////////////////////////////////////////////////////////////////////
ArrayList objToDelete = new ArrayList();    
NucleusRH.Base.Organizacion.Estudios.ESTUDIO objEst;
foreach(NucleusRH.Base.Postulantes.CV.ESTUDIO_CV obj_estudio in objCV.ESTUDIOS_CV) 
{
	switch (obj_estudio.oi_nivel_estudio)
	{
		case "1":
		case "2":
		case "3":
			obj_estudio.oi_nivel_estudio = XML_CV.FirstChild().GetAttr("c_primaria");	
			if(XML_CV.FirstChild().GetAttrInt("c_primaria") == 2)
				obj_estudio.oi_estado_est = "3";
			else
				obj_estudio.oi_estado_est = "1";
			XML_CV.FirstChild().SetAttr("c_primaria", "");
		break;
		case "4":
		case "5":
			if (XML_CV.FirstChild().GetAttrInt("c_secundaria") != 0) 
			{
				obj_estudio.oi_nivel_estudio = XML_CV.FirstChild().GetAttr("c_secundaria");
				if (XML_CV.FirstChild().GetAttr("oi_estudio_secundario") != "")
				{
					obj_estudio.oi_estudio = XML_CV.FirstChild().GetAttr("oi_estudio_secundario");
					objEst = NucleusRH.Base.Organizacion.Estudios.ESTUDIO.Get(XML_CV.FirstChild().GetAttr("oi_estudio_secundario"));
					obj_estudio.oi_area_est = objEst.oi_area_est;
				}
				if(XML_CV.FirstChild().GetAttrInt("c_secundaria") == 4)
					obj_estudio.oi_estado_est = "3";
				else
					obj_estudio.oi_estado_est = "1";
				XML_CV.FirstChild().SetAttr("c_secundaria", "");
			}
			else
				objToDelete.Add(obj_estudio);
		break;
		case "10":
		case "11":
			if (XML_CV.FirstChild().GetAttrInt("c_terciario") != 0)
			{
				obj_estudio.oi_nivel_estudio = XML_CV.FirstChild().GetAttr("c_terciario");
				if (XML_CV.FirstChild().GetAttr("oi_estudio_terciario") != "")
				{
					obj_estudio.oi_estudio = XML_CV.FirstChild().GetAttr("oi_estudio_terciario");
					objEst = NucleusRH.Base.Organizacion.Estudios.ESTUDIO.Get(XML_CV.FirstChild().GetAttr("oi_estudio_terciario"));
					obj_estudio.oi_area_est = objEst.oi_area_est;
				}                
				if(XML_CV.FirstChild().GetAttrInt("c_terciario") == 10)
					obj_estudio.oi_estado_est = "3";
				else
					obj_estudio.oi_estado_est = "1";
				XML_CV.FirstChild().SetAttr("c_terciario", "");
			}
			else
				objToDelete.Add(obj_estudio);
		break;
		case "12":
		case "13":                                                
			if(obj_estudio.o_estudio == "Maestria/Postgrado") 
			{
				if (XML_CV.FirstChild().GetAttrInt("c_maestria") != 0) 
				{
					obj_estudio.oi_nivel_estudio = XML_CV.FirstChild().GetAttr("c_maestria");
					obj_estudio.o_estudio        = "Maestria/Postgrado - " + XML_CV.FirstChild().GetAttr("d_estudio_maestria");
					if(XML_CV.FirstChild().GetAttrInt("c_maestria") == 12)
						obj_estudio.oi_estado_est = "3";
					else
						obj_estudio.oi_estado_est = "1";
					XML_CV.FirstChild().SetAttr("c_maestria", "");
				}
				else
					objToDelete.Add(obj_estudio);
			}
			else
			{
				if (XML_CV.FirstChild().GetAttrInt("c_universitario") != 0) 
				{
					obj_estudio.oi_nivel_estudio = XML_CV.FirstChild().GetAttr("c_universitario");
					if (XML_CV.FirstChild().GetAttr("oi_estudio_terciario") != "")
					{
						obj_estudio.oi_estudio = XML_CV.FirstChild().GetAttr("oi_estudio_universitario");
						objEst = NucleusRH.Base.Organizacion.Estudios.ESTUDIO.Get(XML_CV.FirstChild().GetAttr("oi_estudio_universitario"));
						obj_estudio.oi_area_est = objEst.oi_area_est;
					}	
					if(XML_CV.FirstChild().GetAttrInt("c_universitario") == 12)
						obj_estudio.oi_estado_est = "3";
					else
						obj_estudio.oi_estado_est = "1";
					XML_CV.FirstChild().SetAttr("c_universitario", "");
				}
				else
					objToDelete.Add(obj_estudio);				
			} 	
		break;
		default:
		/////////////// En caso de que tenga otro oi_nivel_estudio que no sea los del switch los borro.
			objToDelete.Add(obj_estudio);
		break;
	}	
}                                     

NucleusRH.Base.Postulantes.CV.ESTUDIO_CV new_estudio;
if (XML_CV.FirstChild().GetAttrInt("c_primaria") != 0) 
{
	new_estudio = new NucleusRH.Base.Postulantes.CV.ESTUDIO_CV();
	new_estudio.oi_nivel_estudio = XML_CV.FirstChild().GetAttr("c_primaria");
	new_estudio.oi_cv            = objCV.id;   
	if(XML_CV.FirstChild().GetAttrInt("c_primaria") == 2)
		new_estudio.oi_estado_est = "3";
	else
		new_estudio.oi_estado_est = "1";
	objCV.ESTUDIOS_CV.Add(new_estudio);
}                                             
if (XML_CV.FirstChild().GetAttrInt("c_secundaria") != 0) 
{
	new_estudio = new NucleusRH.Base.Postulantes.CV.ESTUDIO_CV();
	new_estudio.oi_nivel_estudio = XML_CV.FirstChild().GetAttr("c_secundaria");
	new_estudio.oi_cv            = objCV.id;   		                               
	if (XML_CV.FirstChild().GetAttr("oi_estudio_secundario")!="")
	{
		new_estudio.oi_estudio       = XML_CV.FirstChild().GetAttr("oi_estudio_secundario");  
		objEst = NucleusRH.Base.Organizacion.Estudios.ESTUDIO.Get(XML_CV.FirstChild().GetAttr("oi_estudio_secundario"));
		new_estudio.oi_area_est      = objEst.oi_area_est;
	}
	if(XML_CV.FirstChild().GetAttrInt("c_secundaria") == 4)
		new_estudio.oi_estado_est = "3";
	else
		new_estudio.oi_estado_est = "1";
	objCV.ESTUDIOS_CV.Add(new_estudio);                                                                                      
}
if (XML_CV.FirstChild().GetAttrInt("c_terciario") != 0) 
{
