NomadLog.Info("Agrego los Idiomas");
////////////////////////////////////////////////////////////////////////////////////////////
////////////////////////             Agrego los Idiomas             ////////////////////////
////////////////////////////////////////////////////////////////////////////////////////////
objToDelete.Clear();            

int count_idioma;
int flag;
//Recorrer todos los idiomas del objCV, para cada uno consultar si el oi_idioma es igual a alguno de los que cargó el postulante en la Web
//en caso de que así sea, actualizar los datos de obj_idioma y en caso de que sea el 4 (otro idioma) actualizar el campo o_idioma
//luego setear en "" los campos que cargó el postulante para no tenerlos más en cuenta.
//Si no existe el idioma dentro de los cargados por el postulante, se agrega a una lista para eliminarlos al final. 
foreach(NucleusRH.Base.Postulantes.CV.IDIOMA_CV obj_idioma in objCV.IDIOMAS_CV) 
{
	flag=0;
	for(count_idioma=1;count_idioma<5;count_idioma++)
	{
		if(obj_idioma.oi_idioma == XML_CV.FirstChild().GetAttr("oi_idioma_"+count_idioma.ToString()) && XML_CV.FirstChild().GetAttrInt("oi_idioma_"+count_idioma.ToString()) != 0 && XML_CV.FirstChild().GetAttrInt("c_habla_"+count_idioma.ToString()) != 0 && XML_CV.FirstChild().GetAttrInt("c_lee_"+count_idioma.ToString()) != 0 && XML_CV.FirstChild().GetAttrInt("c_escribe_"+count_idioma.ToString()) != 0)
		{
			flag=1;
			obj_idioma.oi_nivel_habla = XML_CV.FirstChild().GetAttr("c_habla_"+count_idioma.ToString());
			obj_idioma.oi_nivel_lee = XML_CV.FirstChild().GetAttr("c_lee_"+count_idioma.ToString());
			obj_idioma.oi_nivel_escribe = XML_CV.FirstChild().GetAttr("c_escribe_"+count_idioma.ToString());

			if(count_idioma==4)
			{
				obj_idioma.o_idioma = XML_CV.FirstChild().GetAttr("d_otro_idioma");
				XML_CV.FirstChild().SetAttr("d_otro_idioma", "");
			}

			XML_CV.FirstChild().SetAttr("c_habla_"+count_idioma.ToString(), "");
			XML_CV.FirstChild().SetAttr("c_lee_"+count_idioma.ToString(), "");
			XML_CV.FirstChild().SetAttr("c_escribe_"+count_idioma.ToString(), "");
			XML_CV.FirstChild().SetAttr("oi_idioma_"+count_idioma.ToString(), "");
		}
	}

	if(flag==0)
		objToDelete.Add(obj_idioma);
}
//Recorrer el XML_CV para cargar los idiomas que no existen el el objCV
NucleusRH.Base.Postulantes.CV.IDIOMA_CV new_idioma; 
for(int i=1;i<4;i++)
{
	if (XML_CV.FirstChild().GetAttr("oi_idioma_"+i.ToString()) != "" && XML_CV.FirstChild().GetAttr("c_habla_"+i.ToString()) != "" && XML_CV.FirstChild().GetAttr("c_lee_"+i.ToString()) != "" && XML_CV.FirstChild().GetAttr("c_escribe_"+i.ToString()) != "")
