		new_idioma.oi_nivel_escribe = XML_CV.FirstChild().GetAttr("c_escribe_"+i.ToString());
		objCV.IDIOMAS_CV.Add(new_idioma);
	}
}

if (XML_CV.FirstChild().GetAttr("d_otro_idioma") != "" && XML_CV.FirstChild().GetAttrInt("c_habla_4") != 0 && XML_CV.FirstChild().GetAttrInt("c_lee_4") != 0 && XML_CV.FirstChild().GetAttrInt("c_escribe_4") != 0)
