NomadLog.Info("Agrego la Experiencia Laboral");
////////////////////////////////////////////////////////////////////////////////////////////
////////////////////////        Agrego la Experiencia Laboral       ////////////////////////
////////////////////////////////////////////////////////////////////////////////////////////
objToDelete.Clear();            
int count_antecedente = 0;
DateTime f_egreso;
DateTime f_ingreso;
int exper;
foreach(NucleusRH.Base.Postulantes.CV.ANTECEDENTE_CV obj_antecedente in objCV.ANTEC_CV) 
{
	count_antecedente ++;
	switch (count_antecedente) 
	{
	case 1:
	case 2:
	case 3:
		if (XML_CV.FirstChild().GetAttr("d_empresa_"+count_antecedente.ToString()) != "" && XML_CV.FirstChild().GetAttrInt("f_ingreso_"+count_antecedente.ToString()) != 0 && XML_CV.FirstChild().GetAttr("d_puesto_"+count_antecedente.ToString()) != "")
		{
			obj_antecedente.d_empresa     = XML_CV.FirstChild().GetAttr("d_empresa_"+count_antecedente.ToString());
			obj_antecedente.d_puesto      = XML_CV.FirstChild().GetAttr("d_puesto_"+count_antecedente.ToString());
			obj_antecedente.f_ingreso     = XML_CV.FirstChild().GetAttrDateTime("f_ingreso_"+count_antecedente.ToString());
			obj_antecedente.f_egreso      = XML_CV.FirstChild().GetAttrDateTime("f_egreso_"+count_antecedente.ToString());
			obj_antecedente.f_egresoNull  = XML_CV.FirstChild().GetAttr("f_egreso_"+count_antecedente.ToString())=="";
			obj_antecedente.oi_area_lab   = XML_CV.FirstChild().GetAttr("oi_area_lab_"+count_antecedente.ToString());
			obj_antecedente.o_tareas      = XML_CV.FirstChild().GetAttr("o_tipo_tareas_"+count_antecedente.ToString());
		if (XML_CV.FirstChild().GetAttr("f_egreso_"+count_antecedente.ToString())!="" && XML_CV.FirstChild().GetAttr("f_ingreso_"+count_antecedente.ToString())!="")
		{
			f_egreso = XML_CV.FirstChild().GetAttrDateTime("f_egreso_"+count_antecedente.ToString());
			f_ingreso = XML_CV.FirstChild().GetAttrDateTime("f_ingreso_"+count_antecedente.ToString());
			exper=(f_egreso.Year * 12 + f_egreso.Month) - (f_ingreso.Year * 12 + f_ingreso.Month);
			obj_antecedente.e_experiencia = exper;
		}
			////Area de experiencia
			//obj_antecedente    = XML_CV.FirstChild().GetAttr("o_tipo_tareas_"+count_idioma.ToString());
			XML_CV.FirstChild().SetAttr("d_empresa_"+count_antecedente.ToString(),"");
			XML_CV.FirstChild().SetAttr("d_puesto_"+count_antecedente.ToString(),"");
			XML_CV.FirstChild().SetAttr("f_ingreso_"+count_antecedente.ToString(),"");
			XML_CV.FirstChild().SetAttr("f_egreso_"+count_antecedente.ToString(),"");
			XML_CV.FirstChild().SetAttr("oi_area_lab_"+count_antecedente.ToString(),"");
			XML_CV.FirstChild().SetAttr("o_tipo_tareas_"+count_antecedente.ToString(),"");
		}
		else
			objToDelete.Add(obj_antecedente);
	break;   
	default:
	/////////////// En caso de que tenga otro oi_area_lab que no sea los del switch los borro.
		objToDelete.Add(obj_antecedente);
	break;
	}
}          


NucleusRH.Base.Postulantes.CV.ANTECEDENTE_CV new_antecedente; 
for(count_antecedente=1;count_antecedente<4;count_antecedente++) 
{
	NomadLog.Info("--count_antecedente-- " + count_antecedente);    
	NomadLog.Info("--d_empresa-- " + XML_CV.FirstChild().GetAttr("d_empresa_"+count_antecedente.ToString()));    
	NomadLog.Info("--f_ingreso-- " + XML_CV.FirstChild().GetAttrInt("f_ingreso_"+count_antecedente.ToString()));    
	NomadLog.Info("--d_puesto-- " + XML_CV.FirstChild().GetAttr("d_puesto_"+count_antecedente.ToString()));    
	if (XML_CV.FirstChild().GetAttr("d_empresa_"+count_antecedente.ToString()) != "" && XML_CV.FirstChild().GetAttrInt("f_ingreso_"+count_antecedente.ToString()) != 0 && XML_CV.FirstChild().GetAttr("d_puesto_"+count_antecedente.ToString()) != "")
	{
		new_antecedente = new NucleusRH.Base.Postulantes.CV.ANTECEDENTE_CV();
		new_antecedente.oi_cv         = objCV.id;   
		new_antecedente.d_empresa     = XML_CV.FirstChild().GetAttr("d_empresa_"+count_antecedente.ToString());
		new_antecedente.d_puesto      = XML_CV.FirstChild().GetAttr("d_puesto_"+count_antecedente.ToString());
		new_antecedente.f_ingreso     = XML_CV.FirstChild().GetAttrDateTime("f_ingreso_"+count_antecedente.ToString());
		new_antecedente.f_egreso      = XML_CV.FirstChild().GetAttrDateTime("f_egreso_"+count_antecedente.ToString());
		new_antecedente.f_egresoNull  = XML_CV.FirstChild().GetAttr("f_egreso_"+count_antecedente.ToString())=="";
		new_antecedente.oi_area_lab   = XML_CV.FirstChild().GetAttr("oi_area_lab_"+count_antecedente.ToString());
		if (XML_CV.FirstChild().GetAttr("f_egreso_"+count_antecedente.ToString())!="" && XML_CV.FirstChild().GetAttr("f_ingreso_"+count_antecedente.ToString())!="")
		{
			f_egreso = XML_CV.FirstChild().GetAttrDateTime("f_egreso_"+count_antecedente.ToString());
			f_ingreso = XML_CV.FirstChild().GetAttrDateTime("f_ingreso_"+count_antecedente.ToString());
			exper=(f_egreso.Year * 12 + f_egreso.Month) - (f_ingreso.Year * 12 + f_ingreso.Month);
			new_antecedente.e_experiencia = exper;
		}
		new_antecedente.o_tareas      = XML_CV.FirstChild().GetAttr("o_tipo_tareas_"+count_antecedente.ToString());
		NomadLog.Info("--new_antecedente-- " + new_antecedente.SerializeAll());    
		objCV.ANTEC_CV.Add(new_antecedente);
	}                                                                                              
}

foreach(NucleusRH.Base.Postulantes.CV.ANTECEDENTE_CV obj_delete in objToDelete)
	objCV.ANTEC_CV.Remove(obj_delete);

NomadLog.Info("Agrego los Conocimientos"); 
////////////////////////////////////////////////////////////////////////////////////////////
////////////////////////        Agrego los Conocimientos info       ////////////////////////
////////////////////////////////////////////////////////////////////////////////////////////
if(nuevoCV != 1)
{
	objToDelete.Clear();
	int count_conoc = 0;    
	int bandera_conoc;
	NomadXML rowCONOC;
	foreach(NucleusRH.Base.Postulantes.CV.CONOC_CV obj_conocimiento in objCV.CONOC_CV)
	{
		count_conoc ++;                                                          
		bandera_conoc = 0;
		for (rowCONOC=(Nomad.NSystem.Proxy.NomadXML)XML_CV.FirstChild().FirstChild().FirstChild(); rowCONOC!= null; rowCONOC=rowCONOC.Next())
		{
			if(obj_conocimiento.oi_conocimiento == rowCONOC.GetAttr("oi_conocimiento"))
			{
				NomadLog.Info("--rowCONOC-- " + rowCONOC.ToString());  
				obj_conocimiento.c_nivel    = rowCONOC.GetAttr("c_nivel_conoc");
				obj_conocimiento.d_conoc_cv = rowCONOC.GetAttr("d_otro_software");
				rowCONOC.SetAttr("c_nivel_conoc", "");
				bandera_conoc = 1;			
			}
		}
		if(bandera_conoc == 0)
			objToDelete.Add(obj_conocimiento);
	}

	NucleusRH.Base.Postulantes.CV.CONOC_CV new_conocimiento;   
	for (rowCONOC=(Nomad.NSystem.Proxy.NomadXML)XML_CV.FirstChild().FirstChild().FirstChild(); rowCONOC!= null; rowCONOC=rowCONOC.Next())
	{
		if(rowCONOC.GetAttr("c_nivel_conoc") != "")
		{
			new_conocimiento = new NucleusRH.Base.Postulantes.CV.CONOC_CV();
			NomadLog.Info("rowCONOC--new " + rowCONOC.ToString());	
			new_conocimiento.oi_conocimiento = rowCONOC.GetAttr("oi_conocimiento");
			new_conocimiento.oi_cv           = objCV.id;   
			new_conocimiento.c_nivel         = rowCONOC.GetAttr("c_nivel_conoc");
			new_conocimiento.d_conoc_cv      = rowCONOC.GetAttr("d_otro_software");  
			objCV.CONOC_CV.Add(new_conocimiento);
		}
	}
	foreach(NucleusRH.Base.Postulantes.CV.CONOC_CV obj_delete in objToDelete) 
		objCV.CONOC_CV.Remove(obj_delete);
}	                                          
NomadLog.Info("objCV:: " + objCV.SerializeAll());
NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV);

//Actualizo campo like para webCV
NucleusRH.Base.Postulantes.CV.CV.SET_CAMPO_LIKE(objCV.Id.ToString(),"A");



////////////////////////////////////////////////////////////////////////////////////////////
