////////////////////////////////////////////////////////////////////////////////////////////  
NomadLog.Info("--1-- ");	
if(nuevoCV == 1) 
{
	//Obtengo el remitente y la dirección del remitente (parámetros del sistema)
	NomadXML nmdXMLParams = new Nomad.NSystem.Proxy.NomadXML("PARAMS");
	nmdXMLParams = NomadEnvironment.QueryNomadXML(CV.Resources.Parametros, "<ROW remitente_des='1' remitente_dir='1'/>").FirstChild();
	NomadLog.Info("nmdXMLParams:: " + nmdXMLParams.ToString());

	//Obtengo los datos del mail a enviar
	NomadXML xmlInfo = new NomadXML("PARAM");
	Hashtable htaMail = GetMails("REGIS", objCV, xmlInfo);

	string ASUNTO = htaMail.ContainsKey("REGIS_ASUNTO") ? (string) htaMail["REGIS_ASUNTO"] : "-" ;
	string CONTENIDO = htaMail.ContainsKey("REGIS_TEXTO") ? (string) htaMail["REGIS_TEXTO"] : "-" ;

	objCV.enviar_mail(objCV.d_email,ASUNTO,CONTENIDO,nmdXMLParams.GetAttrString("remitente_des"),nmdXMLParams.GetAttrString("remitente_dir"));
}

docUSUARIO.AddXML(NomadEnvironment.QueryNomadXML(CV.Resources.getDatosUsuario, param).FirstChild());
docUSUARIO.SetAttr("oi_cv", objCV.id);
NomadLog.Info("--SAVE--" + objCV.SerializeAll());    
return docUSUARIO;

					NomadEnvironment.GetTrace().Info("****** Buscar Ofertas Laborales ******");

NomadXML docOFERTAS = new Nomad.NSystem.Proxy.NomadXML("OFERTAS");     
string param = "<ROW d_oferta_lab = '" + XML_LOGIN.FirstChild().GetAttr("d_oferta_lab") + "' oi_seniority = '" + XML_LOGIN.FirstChild().GetAttr("oi_seniority") + "' oi_area_lab = '" + XML_LOGIN.FirstChild().GetAttr("oi_area_lab") + "' f_oferta_lab = '" + XML_LOGIN.FirstChild().GetAttr("f_oferta_lab") + "'/>";     
NomadEnvironment.GetTrace().Info("param: " + param.ToString());

docOFERTAS = NomadEnvironment.QueryNomadXML(CV.Resources.getOfertas, param).FirstChild();
NomadEnvironment.GetTrace().Info("docOFERTAS: " + docOFERTAS.ToString());
if(docOFERTAS.GetAttrString("vacio") != "1") {
	docOFERTAS.SetAttr("out","OK");
	return docOFERTAS;                           
}
else {
	docOFERTAS.SetAttr("out","No se encontraron Ofertas Laborales con los filtros ingresados.");
	return docOFERTAS;
}

qry:select.qry:xquery:
		for $r in sql('
	SELECT 
		POS03_OFERTAS_LAB.oi_oferta_lab,
		POS03_OFERTAS_LAB.c_oferta_lab,
		POS03_OFERTAS_LAB.d_oferta_lab,
		POS03_OFERTAS_LAB.o_oferta_lab,
		POS03_OFERTAS_LAB.f_oferta_lab,
		POS03_OFERTAS_LAB.c_sexo,
		ORG35_PROVINCIAS.d_provincia,
		{%? (#SOURCE:@oi_seniority!='')	
			{% POS04_SENIORITY.c_seniority,
				 POS04_SENIORITY.d_seniority, %} 
			{%  %} 
		%}
		{%? (#SOURCE:@oi_area_lab!='')	
			{% POS05_AREAS_LAB.c_area_lab,
				 POS05_AREAS_LAB.d_area_lab,%} 
			{%  %} 
		%}
		POS03_OFERTAS_LAB.oi_localidad,
		POS03_OFERTAS_LAB.d_mail
	FROM 
		POS03_OFERTAS_LAB,
		ORG35_PROVINCIAS
		{%? (#SOURCE:@oi_seniority!='')	
			{% ,POS04_SENIORITY %} 
			{%  %} 
		%}
		{%? (#SOURCE:@oi_area_lab!='')	
			{% ,POS05_AREAS_LAB %} 
			{%  %} 
		%}
	WHERE   
	1=1
		{%? (#SOURCE:@d_oferta_lab!='')	
			{% AND (contain(POS03_OFERTAS_LAB.d_oferta_lab, \'{%= #SOURCE:@d_oferta_lab%}\')
				 OR  contain(POS03_OFERTAS_LAB.c_oferta_lab, \'{%= #SOURCE:@d_oferta_lab%}\')
				 OR  contain(POS03_OFERTAS_LAB.o_oferta_lab, \'{%= #SOURCE:@d_oferta_lab%}\') )
			 %} 
			{% %} 
		%}
		{%? (#SOURCE:@f_oferta_lab!='')	
			{% AND POS03_OFERTAS_LAB.f_oferta_lab >= {Datetime(#SOURCE:@f_oferta_lab)} %} 
			{%  %} 
		%}
		{%? (#SOURCE:@oi_seniority!='')	
			{% AND POS03_OFERTAS_LAB.oi_seniority = POS04_SENIORITY.oi_seniority
				 AND POS04_SENIORITY.oi_seniority = {#SOURCE:@oi_seniority}
			%} 
			{%  %} 
		%}
		{%? (#SOURCE:@oi_area_lab!='')	
			{% AND POS03_OFERTAS_LAB.oi_area_lab = POS05_AREAS_LAB.oi_area_lab
				 AND POS05_AREAS_LAB.oi_area_lab = {#SOURCE:@oi_area_lab}
			%} 
			{%  %} 
		%}         
')/ROWS/ROW

