					NomadLog.Info("****** Comienza el método Postularse******");

XML_OF_LAB=XML_OF_LAB.FirstChild();
NomadLog.Info("XML_OF_LAB: " + XML_OF_LAB.ToString());
NomadXML xmlInfo;

//Recupero el CV
NucleusRH.Base.Postulantes.CV.CV objCV = NucleusRH.Base.Postulantes.CV.CV.Get(XML_OF_LAB.GetAttr("oi_cv"));
NomadLog.Info("objCV-1: " + objCV.SerializeAll());

string strOut="";
//Controlo que el CV no se encuentre postulado a la oferta laboral
foreach(NucleusRH.Base.Postulantes.CV.POSTULACIONES obj_postulacion in objCV.POSTU_CV)
{
	if(obj_postulacion.oi_oferta_lab == XML_OF_LAB.GetAttr("oi_oferta_lab"))
	{
		XML_OF_LAB.SetAttr("out", strOut);
		return XML_OF_LAB;
	}
}

//Agrego la postulación al CV
NucleusRH.Base.Postulantes.CV.POSTULACIONES new_postulacion = new NucleusRH.Base.Postulantes.CV.POSTULACIONES();
new_postulacion.f_postulacion      = DateTime.Now;
new_postulacion.oi_oferta_lab      = XML_OF_LAB.GetAttr("oi_oferta_lab");
new_postulacion.oi_usuario_sistema = XML_OF_LAB.GetAttr("oi_usuario_sistema");
objCV.POSTU_CV.Add(new_postulacion);                               

NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV);

////////////////////////////////////////////////////////////////////////////////////////////
////////////////////////         Envío mails al postularse          ////////////////////////
////////////////////////////////////////////////////////////////////////////////////////////
NomadXML xmlParam = new NomadXML("PARAM");
xmlParam.SetAttr("oi_oferta_lab", XML_OF_LAB.GetAttr("oi_oferta_lab"));
//Obtengo los datos de la oferta laboral
xmlInfo = NomadEnvironment.QueryNomadXML(NucleusRH.Base.Postulantes.Ofertas_Laborales.OFERTA_LAB.Resources.infoOfertaLaboral, xmlParam.ToString()).FirstChild();

//Obtengo los datos del mail a enviar
Hashtable htaMail = GetMails("POSTU", objCV, xmlInfo);

string ASUNTO = htaMail.ContainsKey("POSTU_ASUNTO") ? (string) htaMail["POSTU_ASUNTO"] : "-" ;
string CONTENIDO = htaMail.ContainsKey("POSTU_TEXTO") ? (string) htaMail["POSTU_TEXTO"] : "-" ;

//Obtengo el remitente y la dirección del remitente (parámetros del sistema)
NomadXML nmdXMLParams = new Nomad.NSystem.Proxy.NomadXML("PARAMS");
nmdXMLParams = NomadEnvironment.QueryNomadXML(CV.Resources.Parametros, "<ROW remitente_des='1' remitente_dir='1'/>").FirstChild();
NomadLog.Info("nmdXMLParams:: " + nmdXMLParams.ToString());

//Envío mail al postulante (CV)
if(objCV.d_email != "")
	objCV.enviar_mail(objCV.d_email,ASUNTO,CONTENIDO,nmdXMLParams.GetAttrString("remitente_des"),nmdXMLParams.GetAttrString("remitente_dir"));

//Controlo que se envíe mail al postularse
