NomadLog.Info("nmdXMLParams:: " + nmdXMLParams.ToString());

if(docUSUARIO.GetAttrString("oi_cv") != "0" && docUSUARIO.GetAttrString("c_password") != "0")
{
    if (docUSUARIO.GetAttrString("d_email") != "")
    {
        objCV = NucleusRH.Base.Postulantes.CV.CV.Get(docUSUARIO.GetAttr("oi_cv"));

        //generar nueva clave  
        Random r = new Random();
        nueva_clave = r.Next(99999999).ToString();  
        NomadLog.Info("nueva_clave:: " + nueva_clave.ToString()); 

        cuerpo = "Su nueva contraseña es: **" + nueva_clave + "**********************";
        NomadLog.Info("cuerpo:: " +  cuerpo.ToString()); 

        //guardo temporalmente la clave a enviar en el mail
        objCV.c_password = nueva_clave;
        NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV);
        NomadLog.Info("guardar clave antes de mail:: " + objCV.c_password);    

        //Obtengo los datos del mail a enviar
        NomadXML xmlInfo = new NomadXML("PARAM");
        Hashtable htaMail = GetMails("RECORD", objCV, xmlInfo);

        string ASUNTO = htaMail.ContainsKey("RECORD_ASUNTO") ? (string)htaMail["RECORD_ASUNTO"] : "-";
        string CONTENIDO = htaMail.ContainsKey("RECORD_TEXTO") ? (string)htaMail["RECORD_TEXTO"] : "-";

        objCV.enviar_mail(docUSUARIO.GetAttrString("d_email"), ASUNTO, CONTENIDO, nmdXMLParams.GetAttrString("remitente_des"), nmdXMLParams.GetAttrString("remitente_dir"));

        //encriptar y guardar nueva clave despues de mandar mail
        objCV.c_password = StringUtil.GetMD5("|" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "|" + nueva_clave +"|");
        NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV); 
        NomadLog.Info("guardar clave despues de mail:: " + objCV.c_password);    

        docSALIDA.SetAttr("out", "OK");
        docSALIDA.SetAttr("MSJ", docUSUARIO.GetAttrString("d_email"));
        return docSALIDA;
    }
    else
    {
        docSALIDA.SetAttr("out", "El e-mail no existe");
        docSALIDA.SetAttr("MSJ", "Ud no posee e-mail. Pongase en contacto con BAYTON para solicitar que carguen su e-mail y envíen su contraseña."); 
        return docSALIDA;
    }  
}
else
{
	docSALIDA.SetAttr("out","El usuario no existe.");  
	docSALIDA.SetAttr("MSJ","El usuario no existe.");
	return docSALIDA;
}

