int correctos=0;
int incorrectos=0;
objBatch.Log("Cantidad a Postular: " + max.ToString());

Nomad.NSystem.Proxy.NomadXML result;

//Setear el progress al inicio
objBatch.SetPro(5);

Nomad.NSystem.Proxy.NomadXML PARAM;

// Para cada ROW del XML
