string cuerpo="";  
string clave_entrada_actual;

NucleusRH.Base.Postulantes.CV.CV objCV;

NomadXML docSALIDA = new Nomad.NSystem.Proxy.NomadXML("OUT");

if(XML_LOGIN.FirstChild().GetAttr("c_password_actual")=="")
{
	docSALIDA.SetAttr("out","Falta completar la contraseña actual.");
	docSALIDA.SetAttr("MSJ","Falta completar la contraseña actual.");
	return docSALIDA;
}

if(XML_LOGIN.FirstChild().GetAttr("c_password_nuevo")=="")
{
	docSALIDA.SetAttr("out","Falta completar la contraseña nueva.");
	docSALIDA.SetAttr("MSJ","Falta completar la contraseña nueva.");
	return docSALIDA;
}

if(XML_LOGIN.FirstChild().GetAttr("c_password_nuevo_confirm")=="")
{
	docSALIDA.SetAttr("out","Falta completar la confirmación de la contraseña nueva.");
	docSALIDA.SetAttr("MSJ","Falta completar la confirmación de la contraseña nueva.");
	return docSALIDA;
}

if(XML_LOGIN.FirstChild().GetAttr("c_password_nuevo")!=XML_LOGIN.FirstChild().GetAttr("c_password_nuevo_confirm"))
{
	docSALIDA.SetAttr("out","La nueva contraseña y la confirmación son distintas.");
	docSALIDA.SetAttr("MSJ","La nueva contraseña y la confirmación son distintas.");
	return docSALIDA;
}

NomadXML docUSUARIO = new Nomad.NSystem.Proxy.NomadXML("USUARIO");
NomadXML nmdXMLParams = new Nomad.NSystem.Proxy.NomadXML("PARAMS");
string param = "<ROW oi_tipo_documento = '" + XML_LOGIN.FirstChild().GetAttr("oi_tipo_documento") + "' c_nro_doc = '" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "' />";

NomadLog.Info("param: " + param.ToString());
docUSUARIO = NomadEnvironment.QueryNomadXML(CV.Resources.getUsuario, param).FirstChild();
nmdXMLParams = NomadEnvironment.QueryNomadXML(CV.Resources.Parametros, "<ROW remitente_des='1' remitente_dir='1'/>").FirstChild();
NomadLog.Info("nmdXMLParams:: " + nmdXMLParams.ToString());

NomadLog.Info("docUSUARIO: " + docUSUARIO.ToString());

if(docUSUARIO.GetAttrString("oi_cv") != "0" && docUSUARIO.GetAttrString("c_password") != "0")
{
	objCV = NucleusRH.Base.Postulantes.CV.CV.Get(docUSUARIO.GetAttr("oi_cv"));

  NomadLog.Info("c_password:: " + docUSUARIO.GetAttrString("c_password").ToString());

  //si la clave guardada está encriptada, se encripta también la clave de entrada 
  if (((docUSUARIO.GetAttrString("c_password").Length == 35) && (docUSUARIO.GetAttrString("c_password").Split('-').Length == 4)))
  {
    clave_entrada_actual = StringUtil.GetMD5("|" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "|" + XML_LOGIN.FirstChild().GetAttr("c_password_actual")+"|");
  }  
  //si la clave guardada no está encriptada, la de entrada queda como venía
  else
  {   clave_entrada_actual = XML_LOGIN.FirstChild().GetAttr("c_password_actual"); }


	NomadLog.Info("clave_entrada_actual:: " + clave_entrada_actual);

	if(objCV.c_password != clave_entrada_actual)
	{
		docSALIDA.SetAttr("out","La contraseña actual es incorrecta.");
		docSALIDA.SetAttr("MSJ","La contraseña actual es incorrecta.");
		return docSALIDA;
	}

	NomadLog.Info("Previo al seteo del pass nuevo y grabar");

	//guarda temporalmente nueva clave para enviar por mail
	objCV.c_password = XML_LOGIN.FirstChild().GetAttr("c_password_nuevo");
	NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV);

	//Obtengo los datos del mail a enviar
	NomadXML xmlInfo = new NomadXML("PARAM");
	Hashtable htaMail = GetMails("CHGPASS", objCV, xmlInfo);

	string ASUNTO = htaMail.ContainsKey("CHGPASS_ASUNTO") ? (string) htaMail["CHGPASS_ASUNTO"] : "-" ;
	string CONTENIDO = htaMail.ContainsKey("CHGPASS_TEXTO") ? (string) htaMail["CHGPASS_TEXTO"] : "-" ;

	objCV.enviar_mail(docUSUARIO.GetAttrString("d_email"),ASUNTO,CONTENIDO,nmdXMLParams.GetAttrString("remitente_des"),nmdXMLParams.GetAttrString("remitente_dir"));

	//encripta nueva clave y guarda 
	objCV.c_password = StringUtil.GetMD5("|" + XML_LOGIN.FirstChild().GetAttr("c_nro_doc") + "|" + XML_LOGIN.FirstChild().GetAttr("c_password_nuevo")+"|");
	NomadEnvironment.GetCurrentTransaction().SaveRefresh(objCV);

	docSALIDA.SetAttr("out","OK");
	docSALIDA.SetAttr("MSJ",docUSUARIO.GetAttrString("d_email"));
	return docSALIDA;
}
else
{
	docSALIDA.SetAttr("out","Error al intentar cambiar la contraseña.");
	docSALIDA.SetAttr("MSJ","Error al intentar cambiar la contraseña.");
	return docSALIDA;
}

